import React from 'react';
import ui from '../res/ui.png';
import girl from '../res/girl.jpg';
import { MdFiberManualRecord } from 'react-icons/md';

export default function Feautres(){
    return(
        <div id="feature" className="featureSection">
                        <h2 className="Shead">Our <span>Features</span></h2>
            <h3 className="wsubHead">This very extraordinary feature can make learning activities more effcient.</h3>
            <div className="fWrapper">
                <div className="fImageHolder">
                    <img className="fImage" src={ui} alt="" />
                </div>

                <div className="fDetail">
                    <h2 className="Shead fHead">A <span>user interface </span>designed for the classroom</h2>

                    <div className="featureList">
                        <span className="fIcon">
                            <MdFiberManualRecord/>
                        </span>
                        <span className="fList">Teachers dont get lost in the grid view and have a
                            dedicated podium space
                        </span>
                    </div>

                    <div className="featureList">
                    <span className="fIcon"><MdFiberManualRecord/></span>
                        <span className="fList">TA's and presenters can be removed from class.
                        </span>
                    </div>

                    <div className="featureList">
                        <span className="fIcon"><MdFiberManualRecord/></span>
                        <span className="fList">Teachers can easily see all students and class data all the time
                        </span>
                    </div>

                </div>
            </div>


            <div className="fWrapper second">
                <div className="fImageHolder second">
                    <img className="fImage second"  src={girl} alt="" />
                </div>

                <div className="fDetail second">
                    <h2 className="Shead fHead second"><span>Tools </span>For Teachers <br /> and Learners</h2>
                    
                    <span className="fdata second">Class has a dynamic set of teaching tools built to be
                    deployed and used during class. teachers can handout assissgmments in real-time for students to
                    complete and submit
                    </span>

                </div>
            </div>
            
        </div>
    )
}